#include<bits/stdc++.h>
using namespace std;
long long a[100010],s[100010],dp[100010][2];
int main()
{
    long long n,k;
    scanf("%lld%lld",&n,&k);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        s[i]=s[i-1]+a[i];
    }
    deque<long long> q;
    q.push_back(0);
    for(long long i=1;i<=n;i++)
    {
        dp[i][0]=max(dp[i-1][0],dp[i-1][1]);
        while(!q.empty()&&q.front()<i-k)
        {
            q.pop_front();
        }
        dp[i][1]=dp[q.front()][0]-s[q.front()]+s[i];
        while(!q.empty()&&dp[i][0]-s[i]>dp[q.back()][0]-s[q.back()])
        {
            q.pop_back();
        }
        q.push_back(i);
    }
    printf("%lld",max(dp[n][0],dp[n][1]));
    return 0;
}
